import argparse
import json
import os
import numpy as np
from cogniplan_env import ExplorationEnv
import heapq


def dijkstra(adj, start):
    N = len(adj)
    dist = [float('inf')] * N
    prev = [None] * N
    dist[start] = 0.0
    pq = [(0.0, start)]
    while pq:
        d, u = heapq.heappop(pq)
        if d > dist[u] + 1e-9:
            continue
        for v, w in adj[u]:
            nd = d + w
            if nd + 1e-9 < dist[v]:
                dist[v] = nd
                prev[v] = u
                heapq.heappush(pq, (nd, v))
    return dist, prev


def build_graph(nodes, robot_pos, cur_neighbors):
    coord_to_idx = {}
    for i, n in enumerate(nodes):
        c = tuple(np.round(np.array(n["coords"], dtype=float), 6))
        coord_to_idx[c] = i
    N = len(nodes)
    adj = [[] for _ in range(N)]
    for i, n in enumerate(nodes):
        for nb in n.get("neighbors", []):
            j = None
            if isinstance(nb, dict):
                nb = nb.get("coords", nb)
            if isinstance(nb, (list, tuple, np.ndarray)):
                c = tuple(np.round(np.array(nb, dtype=float), 6))
                j = coord_to_idx.get(c)
            else:
                try:
                    j = int(nb)
                    if not (0 <= j < N):
                        j = None
                except (ValueError, TypeError):
                    j = None
            if j is not None and j != i:
                w = float(np.linalg.norm(
                    np.array(n["coords"], dtype=float) -
                    np.array(nodes[j]["coords"], dtype=float)
                ))
                adj[i].append((j, w))
    r_idx = N
    adj.append([])
    for nb in cur_neighbors:
        c = tuple(np.round(np.array(nb, dtype=float), 6))
        j = coord_to_idx.get(c)
        if j is None:
            continue
        w = float(np.linalg.norm(
            np.array(robot_pos, dtype=float) -
            np.array(nb, dtype=float)
        ))
        adj[r_idx].append((j, w))
        adj[j].append((r_idx, w))
    return adj, coord_to_idx, r_idx


class SimpleGreedyPlanner:
    def __init__(self):
        self.step_count = 0
        self.recent_positions = []

    def reset(self):
        self.step_count = 0
        self.recent_positions = []

    def plan(self, obs):
        self.step_count += 1
        robot_pos = np.array(obs["robot_pos"], dtype=np.float32)
        neighbors = obs["neighbors"]
        nodes = obs["nodes"]
        frontiers = obs.get("frontiers", [])

        self.recent_positions.append(robot_pos.copy())
        if len(self.recent_positions) > 20:
            self.recent_positions.pop(0)

        if not neighbors:
            return None

        adj, coord_to_idx, r_idx = build_graph(nodes, robot_pos, neighbors)
        dist, prev = dijkstra(adj, r_idx)
        N = len(nodes)

        node_to_nb = {}
        for idx, nb in enumerate(neighbors):
            j = coord_to_idx.get(tuple(np.round(np.array(nb, dtype=float), 6)))
            if j is not None:
                node_to_nb[j] = idx

        best_score = -1.0
        best_node = None
        remaining_steps = 128 - self.step_count

        for j in range(N):
            if j == r_idx:
                continue
            d = dist[j]
            if d == float('inf') or d < 1e-6:
                continue
            utility = float(nodes[j].get("utility", 0.0))
            if utility <= 0:
                continue

            score = utility / (d + 1.0)

            if bool(nodes[j].get("visited", False)):
                score *= 0.1

            est_steps = d / 3.2
            if est_steps > remaining_steps:
                score = -1.0

            if score > best_score:
                best_score = score
                best_node = j

        if best_node is None or best_score <= 0:
            if frontiers:
                best_idx = None
                best_dist = float('inf')
                for idx, nb in enumerate(neighbors):
                    nb_arr = np.array(nb, dtype=float)
                    for f in frontiers:
                        d = np.linalg.norm(nb_arr - np.array(f, dtype=float))
                        if d < best_dist:
                            best_dist = d
                            best_idx = idx
                if best_idx is not None:
                    return tuple(float(x) for x in neighbors[best_idx])
            best_idx = 0
            best_dist = -1.0
            for idx, nb in enumerate(neighbors):
                nb_arr = np.array(nb, dtype=float)
                if self.recent_positions:
                    d = min(np.linalg.norm(nb_arr - p) for p in self.recent_positions)
                else:
                    d = 0.0
                if d > best_dist:
                    best_dist = d
                    best_idx = idx
            return tuple(float(x) for x in neighbors[best_idx])

        cur = best_node
        for _ in range(N + 5):
            if prev[cur] == r_idx or prev[cur] is None:
                break
            cur = prev[cur]

        if prev[cur] == r_idx and cur in node_to_nb:
            return tuple(float(x) for x in neighbors[node_to_nb[cur]])

        return tuple(float(x) for x in neighbors[0])


def run_episode(env, planner):
    obs = env.reset()
    planner.reset()
    for _ in range(128):
        target = planner.plan(obs)
        if target is None:
            break
        obs, info = env.step(target)
        if info.get("done"):
            break
    return env.get_metrics()


def infer_env_type(map_path):
    lower = map_path.lower()
    if "room" in lower:
        return "room"
    if "tunnel" in lower:
        return "tunnel"
    if "outdoor" in lower:
        return "outdoor"
    return "unknown"


def main():
    parser = argparse.ArgumentParser()
    parser.add_argument("--data_path", required=True)
    parser.add_argument("--checkpoint", required=True)
    parser.add_argument("--output", required=True)
    args = parser.parse_args()

    ckpt_path = os.path.join(args.checkpoint, "policy.pt")
    if os.path.exists(ckpt_path):
        import torch
        torch.load(ckpt_path, map_location="cpu")

    data_path = args.data_path
    eval_config_path = os.path.join(data_path, "eval_config.json")
    maps_dir = os.path.join(data_path, "maps_eval")

    episodes = []
    if os.path.exists(eval_config_path):
        with open(eval_config_path, "r") as f:
            config = json.load(f)
        if isinstance(config, list):
            if config and isinstance(config[0], str):
                episodes = [{"map_path": p, "env_type": infer_env_type(p)} for p in config]
            else:
                episodes = config
        elif isinstance(config, dict):
            if "episodes" in config:
                episodes = config["episodes"]
            elif "maps" in config:
                episodes = config["maps"]

    if not episodes:
        for env_type in ["room", "tunnel", "outdoor"]:
            subdir = os.path.join(maps_dir, env_type)
            if not os.path.isdir(subdir):
                continue
            for fname in sorted(os.listdir(subdir)):
                if fname.endswith(".png"):
                    episodes.append({
                        "map_path": os.path.join("maps_eval", env_type, fname),
                        "env_type": env_type
                    })

    planner = SimpleGreedyPlanner()
    per_episode = []
    per_type = {}
    total_explored = 0.0
    total_dist_success = 0.0
    n_success = 0
    n_total = 0

    for ep in episodes:
        map_path = ep.get("map_path", ep.get("map", ""))
        if not os.path.isabs(map_path):
            map_path = os.path.join(data_path, map_path)
        env_type = ep.get("env_type", "")
        if not env_type:
            env_type = infer_env_type(map_path)

        env = ExplorationEnv(map_path=map_path)
        metrics = run_episode(env, planner)
        success = 1 if metrics.get("success") else 0
        explored = float(metrics.get("explored_rate", 0.0))
        distance = float(metrics.get("travel_distance", 0.0))

        per_episode.append({
            "map_path": ep.get("map_path", ep.get("map", "")),
            "env_type": env_type,
            "success": success,
            "travel_distance": distance,
            "explored_rate": explored
        })

        total_explored += explored
        n_total += 1
        if success:
            n_success += 1
            total_dist_success += distance

        if env_type not in per_type:
            per_type[env_type] = {"explored": 0.0, "dist_success": 0.0, "success": 0, "count": 0}
        per_type[env_type]["explored"] += explored
        if success:
            per_type[env_type]["dist_success"] += distance
        per_type[env_type]["success"] += success
        per_type[env_type]["count"] += 1

    result = {
        "explored_rate": total_explored / n_total if n_total > 0 else 0.0,
        "travel_distance": total_dist_success / n_success if n_success > 0 else 0.0,
        "success_rate": n_success / n_total if n_total > 0 else 0.0,
        "per_episode": per_episode,
        "per_type": {},
        "total_episodes": n_total
    }

    for env_type, stats in per_type.items():
        c = stats["count"]
        result["per_type"][env_type] = {
            "explored_rate": stats["explored"] / c if c > 0 else 0.0,
            "travel_distance": stats["dist_success"] / stats["success"] if stats["success"] > 0 else 0.0,
            "success_rate": stats["success"] / c if c > 0 else 0.0
        }

    with open(args.output, "w") as f:
        json.dump(result, f, indent=2)


if __name__ == "__main__":
    main()
